use std::collections::HashMap;

struct DungeonCell {
    is_wall: bool,
    room_id: Option<u32>,
}

struct DungeonMap {
    cells: HashMap<String, DungeonCell>,
}

impl DungeonMap {
    fn new() -> Self {
        DungeonMap { 
            cells: HashMap::new()
        }
    }

    fn add_cell(&mut self, key: String, cell: DungeonCell) {
        self.cells.insert(key, cell);
    }
}

fn main() {
    let mut map = DungeonMap::new();
    map.add_cell("A1".to_string(), DungeonCell { is_wall: false, room_id: Some(1) });
    map.add_cell("A2".to_string(), DungeonCell { is_wall: true, room_id: None });
    map.add_cell("B1".to_string(), DungeonCell { is_wall: false, room_id: Some(1) });

    let processed_cells: Vec<String> = map.cells.iter()
        .filter(|(_, cell)| !cell.is_wall)
        .map(|(key, _)| key.clone()) 
        .collect();

    println!("Found {} open locations.", processed_cells.len());
}

use std::collections::HashMap;
use std::thread;
use std::sync::{Arc, Mutex};

struct Document {
    id: u32,
    content: String,
}
impl Document {
    fn new(id: u32, content: &str) -> Self {
        Document { id, content: content.to_string() }
    }
}

struct ValidatorState {
    shared_counter: Arc<Mutex<i32>>,
    processed_ids: Mutex<HashMap<u32, bool>>
}

fn validate_document(doc: Arc<Document>, state: Arc<ValidatorState>) -> bool {
    let mut counter = state.shared_counter.lock().unwrap();
    *counter += 1;
    println!("Processing document {}... Current global count: {}", doc.id, *counter);

    let mut processed = state.processed_ids.lock().unwrap();
    if processed.contains_key(&doc.id) {
        return false;
    }
    processed.insert(doc.id, true);

    thread::sleep(std::time::Duration::from_millis(10));
    true
}

fn main() {
    let docs = vec![ 
        Arc::new(Document::new(101, "Schema v2.1")),
        Arc::new(Document::new(102, "Operation A details")),
        Arc::new(Document::new(103, "Error handling rules"))
    ];

    let state = Arc::new(ValidatorState {
        shared_counter: Arc::new(Mutex::new(0)),
        processed_ids: Mutex::new(HashMap::new()),
    });

    let mut handles = vec![];

    for doc in docs { 
        let state_clone = Arc::clone(&state);
        let doc_clone = Arc::clone(&doc);
        let handle = thread::spawn(move || {
            validate_document(doc_clone, state_clone)
        });
        handles.push(handle);
    }

    for handle in handles {
        let _ = handle.join();
    }
    println!("nValidation complete.");
}

use std::collections::VecDeque;
use std::collections::HashSet;
use std::collections::HashMap;

struct MapNode {
    id: usize,
    connections: Vec<usize>,
}

struct GameMapTree {
    nodes: HashMap<usize, MapNode>,
}

impl GameMapTree {
    fn new() -> Self {
        GameMapTree { nodes: HashMap::new() }
    }

    fn add_node(&mut self, id: usize, connections: Vec<usize>) {
        self.nodes.insert(id, MapNode { id, connections });
    }
}

struct TreeIterator<'a> {
    map: &'a GameMapTree,
    start_node_id: usize,
    visited: HashSet<usize>,
    queue: VecDeque<usize>,
}

impl<'a> Iterator for TreeIterator<'a> {
    type Item = usize;

    fn next(&mut self) -> Option<Self::Item> {
        if let Some(current_id) = self.queue.pop_front() {
            if !self.visited.contains(&current_id) {
                self.visited.insert(current_id);
                let result = Some(current_id);

                let mut new_neighbors = Vec::new();
                if let Some(node) = self.map.nodes.get(&current_id) {
                    for &neighbor_id in node.connections.iter() {
                        if !self.visited.contains(&neighbor_id) && !new_neighbors.contains(&neighbor_id) {
                            new_neighbors.push(neighbor_id);
                        }
                    }
                }

                for neighbor_id in new_neighbors {
                    self.queue.push_back(neighbor_id);
                }
                Some(result.unwrap())
            } else {
                None
            }
        } else {
            None
        }
    }
}

fn main() {
    let mut map = GameMapTree::new();
    map.add_node(1, vec![2, 3]);
    map.add_node(2, vec![1, 4]);
    map.add_node(3, vec![1, 5]);
    map.add_node(4, vec![2]);
    map.add_node(5, vec![3]);

    let start_id = 1;
    let mut tree_iter = TreeIterator { 
        map: &map,
        start_node_id: start_id,
        visited: HashSet::new(),
        queue: VecDeque::from(vec![start_id]),
    };

    println!("Traversing map starting from node {}:", start_id);
    for id in tree_iter.by_ref() {
        println!("Found tile ID: {}", id);
    }
}
